namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, ErrorMessage = "Name cannot exceed 100 characters.")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^STU-\d{5}$", ErrorMessage = "Student ID must be in the format STU-XXXXX (e.g., STU-12345).")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    Department? GetDepartment(int id);
    List<Course> GetCourses(string? search, int? departmentId);
    Course? GetCourse(int id);
    List<Course> GetFeaturedCourses();
    void SubmitEnrollmentRequest(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Description = "Study of computation, algorithms, and software systems." },
            new() { Id = 2, Name = "Mathematics", Description = "Exploration of abstract structures, patterns, and quantitative reasoning." },
            new() { Id = 3, Name = "English", Description = "Analysis of literature, writing, and language arts." },
            new() { Id = 4, Name = "Physics", Description = "Investigation of matter, energy, and the fundamental forces of nature." }
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, DepartmentId = 1, Code = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 10:00-10:50", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory programming and has published extensively on CS education pedagogy.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, Code = "CS201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures including arrays, linked lists, trees, and graphs. Analysis of algorithm complexity and design patterns.", Credits = 4, Schedule = "TTh 9:00-10:20", InstructorName = "Dr. James Rodriguez", InstructorBio = "Dr. Rodriguez specializes in algorithm optimization and has contributed to several open-source projects.", IsFeatured = false },
            new() { Id = 3, DepartmentId = 1, Code = "CS340", Title = "Database Systems", Description = "Introduction to relational databases, SQL, normalization, and transaction processing. Includes hands-on projects with modern database technologies.", Credits = 3, Schedule = "MWF 1:00-1:50", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked in industry for a decade at major tech companies before joining academia. She specializes in distributed database systems.", IsFeatured = true },

            // Mathematics
            new() { Id = 4, DepartmentId = 2, Code = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "MWF 9:00-9:50", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator who has taught calculus for over 20 years and authored two popular textbooks.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations with applications.", Credits = 3, Schedule = "TTh 11:00-12:20", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on applied linear algebra and numerical methods for scientific computing.", IsFeatured = false },
            new() { Id = 6, DepartmentId = 2, Code = "MATH310", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "MWF 2:00-2:50", InstructorName = "Dr. Alan Park", InstructorBio = "Dr. Park combines his background in actuarial science with academic research in statistical modeling.", IsFeatured = false },

            // English
            new() { Id = 7, DepartmentId = 3, Code = "ENG101", Title = "Composition and Rhetoric", Description = "Development of academic writing skills including argumentation, research methods, and critical analysis of texts.", Credits = 3, Schedule = "MWF 11:00-11:50", InstructorName = "Prof. Diana Mitchell", InstructorBio = "Prof. Mitchell is a published author and writing consultant who emphasizes practical writing skills for professional success.", IsFeatured = false },
            new() { Id = 8, DepartmentId = 3, Code = "ENG220", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present, exploring themes of identity and culture.", Credits = 3, Schedule = "TTh 2:00-3:20", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant is a specialist in 20th-century American fiction and has published three books on the American literary canon.", IsFeatured = true },
            new() { Id = 9, DepartmentId = 3, Code = "ENG315", Title = "Creative Writing Workshop", Description = "Workshop-based course focusing on fiction and poetry. Students produce original works and participate in peer review.", Credits = 3, Schedule = "W 6:00-8:50 PM", InstructorName = "Prof. Lisa Chang", InstructorBio = "Prof. Chang is an award-winning poet and novelist whose work has appeared in numerous literary journals.", IsFeatured = false },

            // Physics
            new() { Id = 10, DepartmentId = 4, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory component with hands-on experiments.", Credits = 4, Schedule = "MWF 8:00-8:50, Lab: F 2:00-4:50", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres brings enthusiasm for experimental physics and has mentored numerous undergraduate research projects.", IsFeatured = false },
            new() { Id = 11, DepartmentId = 4, Code = "PHYS201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "TTh 10:00-11:20, Lab: T 2:00-4:50", InstructorName = "Dr. Rachel Foster", InstructorBio = "Dr. Foster's research in photonics has been funded by multiple national grants and she holds several patents.", IsFeatured = true },
            new() { Id = 12, DepartmentId = 4, Code = "PHYS350", Title = "Quantum Mechanics", Description = "Wave-particle duality, Schrödinger equation, quantum states, and measurement theory.", Credits = 3, Schedule = "MWF 3:00-3:50", InstructorName = "Dr. David Nguyen", InstructorBio = "Dr. Nguyen is a theoretical physicist whose work on quantum information theory bridges physics and computer science.", IsFeatured = false }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist the enrollment request
    }
}

