@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Home - University Course Catalog</PageTitle>

<div class="text-center py-5 bg-light rounded mb-4">
    <h1 class="display-4">Westfield University</h1>
    <p class="lead">Explore our course catalog and find the classes that shape your future.</p>
    <a href="courses" class="btn btn-primary btn-lg">Browse All Courses</a>
</div>

<h2 class="mb-3">Featured Courses</h2>
<div class="row mb-5">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Title</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Code</h6>
                    <p class="card-text">Credits: @course.Credits</p>
                    <a href="courses/@course.Id" class="btn btn-outline-primary">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mb-3">Departments</h2>
<div class="list-group mb-4">
    @foreach (var dept in departments)
    {
        <a href="courses?departmentId=@dept.Id" class="list-group-item list-group-item-action">
            <strong>@dept.Name</strong> &mdash; @dept.Description
        </a>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@if (courses.Any())
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                var dept = CatalogService.GetDepartment(course.DepartmentId);
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@dept?.Name</td>
                    <td>@course.Credits</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <div class="alert alert-info">No courses found matching your criteria. Try adjusting your search or filter.</div>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

