@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enroll - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Model.Name</strong>. Your enrollment request for the selected course has been received. You will receive a confirmation at your university email.</p>
        <a href="courses" class="btn btn-primary">Back to Courses</a>
    </div>
}
else
{
    <p>Fill out the form below to submit an enrollment request.</p>

    <form method="post" class="needs-validation">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="name" class="form-label">Full Name</label>
            <input type="text" id="name" name="Model.Name" value="@Model.Name" class="form-control" required />
            @if (errors.ContainsKey(nameof(Model.Name)))
            {
                <div class="text-danger">@errors[nameof(Model.Name)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" placeholder="STU-XXXXX" required />
            @if (errors.ContainsKey(nameof(Model.StudentId)))
            {
                <div class="text-danger">@errors[nameof(Model.StudentId)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Code - @course.Title</option>
                }
            </select>
            @if (errors.ContainsKey(nameof(Model.CourseId)))
            {
                <div class="text-danger">@errors[nameof(Model.CourseId)]</div>
            }
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    private List<Course> courses = new();
    private Dictionary<string, string> errors = new();
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses(null, null);

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    // This method handles the form POST
    [SupplyParameterFromForm(Name = "")]
    private string? _handler { get; set; }

    // We need to handle form post via OnInitialized by checking if it's a POST
}

